      instructions = "1. Soak cedar plank in water for at least 2 hours.\n2. Mix brown sugar, soy sauce and garlic powder.\n3. Brush over salmon fillets.\n4. Place salmon on plank.\n5. Grill covered at 400F for 15-18 minutes.\n6. Serve with lemon and dill.",
      fact = "Fun Fact: Washington State produces more salmon than any other state in the contiguous US."
    ),
    "West Virginia" = list(
      name = "West Virginia Pepperoni Roll",
      desc = "Soft, pillowy bread rolls stuffed with spicy pepperoni — a West Virginia coal miner staple.",
      ingredients = "- 1 lb bread dough\n- 1/2 lb pepperoni, sliced\n- 1 cup mozzarella, shredded\n- Italian seasoning\n- Butter for brushing",
      instructions = "1. Divide dough into 8 pieces.\n2. Roll each piece flat.\n3. Layer pepperoni and cheese in center.\n4. Roll up and pinch to seal.\n5. Bake at 375F for 20 minutes.\n6. Brush with butter when hot.",
      fact = "Fun Fact: The pepperoni roll was invented in 1927 in Fairmont, WV as a portable lunch for coal miners."
    ),
    "Wisconsin" = list(
      name = "Wisconsin Beer Brats",
      desc = "Bratwurst simmered in Wisconsin beer and onions then grilled to perfection.",
      ingredients = "- 6 bratwurst\n- 2 cans Wisconsin lager beer\n- 2 onions, sliced\n- 2 tbsp butter\n- Brat buns\n- Sauerkraut and spicy mustard",
      instructions = "1. Simmer brats in beer and onions for 20 minutes.\n2. Remove and grill over high heat until charred, about 5 minutes.\n3. Cook down beer and onions until caramelized.\n4. Serve brats on buns with onions, sauerkraut and mustard.",
      fact = "Fun Fact: Wisconsin consumes more bratwurst per capita than any other state, with Sheboygan called the Bratwurst Capital of the World."
    ),
    "Wyoming" = list(
      name = "Wyoming Elk Steak",
      desc = "A simply seasoned elk steak grilled over high heat — pure Wyoming wilderness on a plate.",
      ingredients = "- 4 elk steaks\n- 2 tbsp olive oil\n- 2 cloves garlic, minced\n- Fresh rosemary\n- Salt and coarse black pepper",
      instructions = "1. Rub steaks with olive oil, garlic, rosemary, salt and pepper.\n2. Let rest 30 minutes at room temperature.\n3. Grill on high 3-4 minutes per side for medium rare.\n4. Rest 5 minutes before serving.\n5. Serve with roasted potatoes.",
      fact = "Fun Fact: Wyoming has one of the largest elk populations in North America, with over 100,000 elk roaming the state."
    )
  ),
  
  # ── COMMERCIALLY PREPARED ITEMS ────────────────────────────────────────────
  "Commercially prepared items" = list(
    "Alabama" = list(name = "Alabama BBQ Nachos", desc = "Tortilla chips loaded with pulled pork, white BBQ sauce and pickled jalapeños.", ingredients = "- Tortilla chips\n- 2 cups pulled pork\n- Alabama white BBQ sauce\n- Pickled jalapeños\n- Shredded cheddar\n- Green onions", instructions = "1. Spread chips on a baking sheet.\n2. Top with pulled pork and cheddar.\n3. Bake at 400F for 10 minutes.\n4. Drizzle with white BBQ sauce.\n5. Top with jalapeños and green onions.", fact = "Fun Fact: Alabama's white BBQ sauce is made with mayo and vinegar — unique in the BBQ world."),
    "Arizona" = list(name = "Arizona Sonoran Hot Dog", desc = "A bacon-wrapped hot dog in a bolillo roll with pinto beans, tomato and mayo.", ingredients = "- 4 hot dogs\n- 4 strips bacon\n- 4 bolillo rolls\n- 1 can pinto beans\n- 2 tomatoes, diced\n- Mayo and mustard", instructions = "1. Wrap each hot dog in bacon and secure with a toothpick.\n2. Grill until bacon is crispy.\n3. Warm bolillo rolls.\n4. Fill with hot dog, beans, tomato, mayo and mustard.", fact = "Fun Fact: The Sonoran hot dog originated in Sonora, Mexico and crossed the border into Tucson where it became iconic."),
    "Arkansas" = list(name = "Arkansas Cheese Dip", desc = "The smooth, creamy cheese dip that Arkansas claims to have invented.", ingredients = "- 1 lb Velveeta\n- 1 can Ro-Tel tomatoes\n- 1/2 lb ground beef, browned\n- Tortilla chips for dipping", instructions = "1. Melt Velveeta in a slow cooker.\n2. Stir in Ro-Tel and browned beef.\n3. Cook on low 1 hour, stirring occasionally.\n4. Serve warm with chips.", fact = "Fun Fact: Arkansas claims to have invented queso dip — Hot Springs is known as the birthplace of cheese dip."),
    "California" = list(name = "California Fish Tacos", desc = "Crispy battered fish in corn tortillas with shredded cabbage and creamy chipotle sauce.", ingredients = "- 1 lb white fish (cod or tilapia)\n- 1 cup flour\n- 1 cup beer\n- Corn tortillas\n- Shredded cabbage\n- 1/2 cup mayo\n- 2 chipotle peppers in adobo\n- Lime", instructions = "1. Make batter with flour and beer.\n2. Dip fish and fry at 375F until golden.\n3. Blend mayo and chipotle for sauce.\n4. Serve fish in tortillas with cabbage, sauce and lime.", fact = "Fun Fact: Fish tacos were popularized in California after surfers discovered them in Baja Mexico in the 1970s."),
    "Colorado" = list(name = "Colorado Green Chile Smothered Burrito", desc = "A fat burrito completely smothered in green chile sauce.", ingredients = "- Large flour tortillas\n- 2 cups cooked rice\n- 1 can black beans\n- 1 cup shredded chicken\n- 2 cups green chile sauce\n- Shredded cheese", instructions = "1. Fill tortillas with rice, beans and chicken.\n2. Roll into burritos and place in baking dish.\n3. Pour green chile sauce over completely.\n4. Top with cheese and bake at 375F for 20 minutes.", fact = "Fun Fact: Colorado's green chile sauce is made from Pueblo or Hatch chiles and is a staple of the state's cuisine."),
    "Connecticut" = list(name = "Connecticut New Haven Pizza", desc = "Thin, charred white clam pizza inspired by New Haven's legendary apizza tradition.", ingredients = "- 1 lb pizza dough\n- 1 can chopped clams\n- 4 cloves garlic, minced\n- Olive oil\n- Oregano\n- Pecorino Romano", instructions = "1. Stretch dough very thin on a floured surface.\n2. Brush with olive oil and garlic.\n3. Top with clams, oregano and cheese.\n4. Bake at 500F on a pizza stone for 8-10 minutes.\n5. The crust should be charred and crispy.", fact = "Fun Fact: New Haven pizza, called 'apizza', is considered by many food critics to be the best pizza in America."),
    "Florida" = list(name = "Florida Cuban Sandwich", desc = "The legendary pressed sandwich with ham, roasted pork, Swiss, pickles and mustard.", ingredients = "- Cuban bread or hoagie rolls\n- Sliced ham\n- Sliced roasted pork\n- Swiss cheese\n- Dill pickles\n- Yellow mustard\n- Butter", instructions = "1. Split bread and spread mustard on both sides.\n2. Layer ham, pork, Swiss and pickles.\n3. Butter the outside of the bread.\n4. Press in a sandwich press or heavy pan until flat and golden.\n5. Slice diagonally.", fact = "Fun Fact: Tampa and Miami argue about who makes the 'real' Cuban sandwich — Tampa adds salami, Miami does not."),
    "Georgia" = list(name = "Georgia Peach Cobbler", desc = "A bubbling, golden peach cobbler with a buttery biscuit topping.", ingredients = "- 6 ripe peaches, sliced\n- 1 cup flour\n- 1 cup sugar (divided)\n- 1 cup milk\n- 1/2 cup butter\n- 1 tsp baking powder\n- Cinnamon", instructions = "1. Melt butter in a baking dish.\n2. Mix flour, 1/2 cup sugar, milk and baking powder.\n3. Pour batter into dish with butter — do not stir.\n4. Toss peaches with remaining sugar and cinnamon.\n5. Spoon peaches over batter — do not stir.\n6. Bake at 350F for 45 minutes.", fact = "Fun Fact: Georgia peaches are picked June through August and are prized for their sweetness and aroma."),
    "Illinois" = list(name = "Chicago Deep Dish Pizza", desc = "The iconic deep dish with layers of sausage, cheese and chunky tomato sauce on top.", ingredients = "- 2 cups flour\n- 1/2 cup cornmeal\n- 1/2 cup butter\n- 1 lb Italian sausage\n- 2 cups mozzarella\n- 1 can crushed tomatoes\n- Garlic and oregano", instructions = "1. Make dough with flour, cornmeal, butter and water.\n2. Press into a deep dish pan up the sides.\n3. Layer sausage and mozzarella.\n4. Season crushed tomatoes with garlic and oregano.\n5. Pour tomatoes on top.\n6. Bake at 425F for 35 minutes.", fact = "Fun Fact: Chicago deep dish was invented at Pizzeria Uno in 1943 by Ike Sewell and Ric Riccardo."),
    "Indiana" = list(name = "Indiana Sugar Cream Pie", desc = "A simple, custardy pie made with cream and sugar — Indiana's official state pie.", ingredients = "- 1 pie crust\n- 2 cups heavy cream\n- 1 cup sugar\n- 1/4 cup flour\n- 1 tsp vanilla\n- Cinnamon for top", instructions = "1. Pre-bake pie crust 10 minutes.\n2. Mix cream, sugar, flour and vanilla until smooth.\n3. Pour into crust.\n4. Dust with cinnamon.\n5. Bake at 400F for 30 minutes until set but slightly jiggly.", fact = "Fun Fact: Sugar cream pie is Indiana's official state pie and has been made by Hoosier farmwives since pioneer times."),
    "Iowa" = list(name = "Iowa Corn on the Cob", desc = "Sweet Iowa corn grilled in the husk and slathered with herb butter.", ingredients = "- 6 ears sweet corn in husk\n- 1/2 cup butter, softened\n- 2 tbsp fresh chives\n- 1 tbsp fresh parsley\n- Salt and pepper", instructions = "1. Soak corn in water 30 minutes.\n2. Grill in husks over medium heat 20 minutes, turning.\n3. Mix butter with herbs, salt and pepper.\n4. Peel back husks and brush with herb butter.\n5. Serve immediately.", fact = "Fun Fact: Iowa grows more corn than any other state, producing over 2 billion bushels per year."),
    "Kansas" = list(name = "Kansas City BBQ Baked Beans", desc = "Smoky, sweet baked beans loaded with burnt ends and thick KC BBQ sauce.", ingredients = "- 2 cans navy beans\n- 1 cup KC BBQ sauce\n- 1/2 lb burnt ends or smoked brisket\n- 1 onion, diced\n- 3 tbsp brown sugar\n- 1 tbsp mustard", instructions = "1. Combine all ingredients in a baking dish.\n2. Stir well to combine.\n3. Bake covered at 325F for 1.5 hours.\n4. Uncover and bake 30 more minutes until thick.", fact = "Fun Fact: Kansas City has more BBQ restaurants per capita than any other city in the US."),
    "Kentucky" = list(name = "Kentucky Bourbon Pecan Pie", desc = "A rich, gooey pecan pie spiked with Kentucky bourbon.", ingredients = "- 1 pie crust\n- 2 cups pecan halves\n- 3 eggs\n- 1 cup corn syrup\n- 1/2 cup sugar\n- 3 tbsp Kentucky bourbon\n- 2 tbsp butter\n- 1 tsp vanilla", instructions = "1. Whisk eggs, corn syrup, sugar, bourbon, butter and vanilla.\n2. Stir in pecans.\n3. Pour into crust.\n4. Bake at 350F for 50-60 minutes until set.", fact = "Fun Fact: Kentucky produces 95% of the world's bourbon whiskey supply."),
    "Louisiana" = list(name = "Louisiana Beignets", desc = "Pillowy, deep-fried dough squares buried under a mountain of powdered sugar.", ingredients = "- 2 cups flour\n- 1 tsp yeast\n- 1/2 cup warm water\n- 1/4 cup sugar\n- 1 egg\n- 1/4 cup evaporated milk\n- Oil for frying\n- Powdered sugar", instructions = "1. Dissolve yeast in warm water.\n2. Mix flour, sugar, egg, milk and yeast mixture.\n3. Knead and let rise 1 hour.\n4. Roll out and cut into squares.\n5. Fry at 370F until golden, about 2 minutes per side.\n6. Bury in powdered sugar.", fact = "Fun Fact: Café Du Monde in New Orleans has been serving beignets 24 hours a day since 1862."),
    "Maine" = list(name = "Maine Blueberry Pie", desc = "A double-crust pie bursting with wild Maine blueberries.", ingredients = "- 4 cups wild Maine blueberries\n- 3/4 cup sugar\n- 3 tbsp cornstarch\n- 1 tsp lemon juice\n- 2 pie crusts\n- Butter and egg wash", instructions = "1. Mix blueberries with sugar, cornstarch and lemon.\n2. Pour into bottom crust.\n3. Dot with butter.\n4. Top with second crust and crimp edges.\n5. Brush with egg wash.\n6. Bake at 425F for 20 minutes, then 350F for 30 minutes.", fact = "Fun Fact: Maine produces 99% of all wild blueberries in the US."),
    "Maryland" = list(name = "Maryland Old Bay Crab Chips", desc = "Homemade potato chips tossed in Old Bay seasoning — a Maryland snack staple.", ingredients = "- 4 large potatoes, sliced paper thin\n- Oil for frying\n- Old Bay seasoning\n- Salt", instructions = "1. Slice potatoes as thin as possible on a mandoline.\n2. Soak in cold water 30 minutes, then dry thoroughly.\n3. Fry in batches at 375F until golden and crispy.\n4. Immediately toss with Old Bay and salt.\n5. Serve warm.", fact = "Fun Fact: Old Bay seasoning was created in Baltimore in 1939 and is the unofficial seasoning of Maryland."),
    "Massachusetts" = list(name = "Massachusetts Clam Chowder", desc = "The classic creamy New England clam chowder with potatoes and bacon.", ingredients = "- 2 cans chopped clams\n- 4 strips bacon, diced\n- 1 onion, diced\n- 3 potatoes, diced\n- 2 cups heavy cream\n- 2 cups clam juice\n- 2 tbsp flour\n- Thyme and bay leaf", instructions = "1. Cook bacon until crispy, set aside.\n2. Saute onion in bacon fat.\n3. Add flour and cook 1 minute.\n4. Add clam juice, potatoes, thyme and bay leaf.\n5. Cook 15 minutes until potatoes are tender.\n6. Add cream and clams, heat through.\n7. Serve topped with bacon.", fact = "Fun Fact: New England clam chowder has been a Massachusetts staple since the 1700s."),
    "Michigan" = list(name = "Michigan Coney Island Hot Dog", desc = "A beef hot dog topped with beanless chili sauce, mustard and onions.", ingredients = "- 6 hot dogs\n- 1 lb ground beef\n- 1 onion, finely diced\n- 1 tbsp chili powder\n- 1 tsp cumin\n- 1/4 tsp allspice\n- Hot dog buns\n- Yellow mustard", instructions = "1. Brown ground beef with onion and spices.\n2. Simmer 20 minutes into a thick sauce.\n3. Grill hot dogs.\n4. Place in buns, top with chili sauce, mustard and raw onion.", fact = "Fun Fact: Detroit has two competing Coney Island restaurants — Lafayette and American — that have faced off across the street since the 1910s."),
    "Minnesota" = list(name = "Minnesota Wild Rice Hot Dish", desc = "The legendary Minnesota comfort food — a casserole with wild rice and cream of mushroom soup.", ingredients = "- 1 cup wild rice\n- 1 lb ground beef\n- 1 can cream of mushroom soup\n- 1 cup sour cream\n- 1 onion, diced\n- 1 cup mushrooms\n- Salt and pepper", instructions = "1. Cook wild rice according to package directions.\n2. Brown beef and onion.\n3. Mix everything together with soup and sour cream.\n4. Pour into a casserole dish.\n5. Bake at 350F for 45 minutes.", fact = "Fun Fact: Wild rice is Minnesota's official state grain and has been a food source for the Ojibwe people for centuries."),
    "Mississippi" = list(name = "Mississippi Mud Cake", desc = "A dense, fudgy chocolate cake topped with marshmallows and chocolate frosting.", ingredients = "- 2 cups flour\n- 2 cups sugar\n- 1 cup butter\n- 1/2 cup cocoa\n- 4 eggs\n- 2 cups mini marshmallows\n- Chocolate frosting", instructions = "1. Melt butter and cocoa together.\n2. Mix in sugar, eggs and flour.\n3. Pour into a greased 9x13 pan.\n4. Bake at 350F for 30 minutes.\n5. While hot, scatter marshmallows on top.\n6. Return to oven 2 minutes until marshmallows puff.\n7. Spread frosting over marshmallows.", fact = "Fun Fact: Mississippi Mud Cake is named for its resemblance to the dark, sticky mud banks of the Mississippi River."),
    "Missouri" = list(name = "Missouri Gooey Butter Cake", desc = "A St. Louis original — a rich, dense cake with a gooey, buttery top layer.", ingredients = "- 1 box yellow cake mix\n- 1/2 cup butter, melted\n- 3 eggs (divided)\n- 8 oz cream cheese, softened\n- 1 lb powdered sugar", instructions = "1. Mix cake mix, melted butter and 1 egg.\n2. Press into a greased 9x13 pan.\n3. Beat cream cheese with 2 eggs and powdered sugar.\n4. Pour cream cheese mixture over base.\n5. Bake at 350F for 40 minutes — center should still jiggle.", fact = "Fun Fact: Gooey butter cake was accidentally invented in St. Louis in the 1930s when a baker mixed up the butter and sugar ratios."),
    "Nebraska" = list(name = "Nebraska Kolache", desc = "Soft, pillowy Czech pastry filled with fruit, poppy seed or sweetened cheese.", ingredients = "- 3 cups flour\n- 1/4 cup sugar\n- 2 tsp yeast\n- 1/2 cup warm milk\n- 1/2 cup butter\n- 2 eggs\n- Fruit jam or cream cheese filling", instructions = "1. Make dough with flour, sugar, yeast, milk, butter and eggs.\n2. Let rise 1 hour.\n3. Form into rounds and indent center.\n4. Fill with jam or cream cheese.\n5. Let rise 20 more minutes.\n6. Bake at 375F for 15 minutes.", fact = "Fun Fact: Nebraska has a large Czech population and hosts a Kolache Festival in Prague, Nebraska each year."),
    "Nevada" = list(name = "Nevada Prime Rib Buffet Style", desc = "Classic Las Vegas-style prime rib with au jus and horseradish cream.", ingredients = "- 5 lb prime rib roast\n- 4 cloves garlic\n- 2 tbsp olive oil\n- Salt, pepper, rosemary\n- 2 cups beef broth\n- Horseradish cream", instructions = "1. Rub roast with oil, garlic, salt, pepper and rosemary.\n2. Roast at 450F for 15 minutes.\n3. Reduce to 325F and roast to 125F internal for medium rare.\n4. Rest 20 minutes.\n5. Deglaze pan with broth for au jus.\n6. Serve with horseradish cream.", fact = "Fun Fact: Las Vegas buffets made prime rib a staple American dining experience, offering it as a value centerpiece since the 1950s."),
    "New Hampshire" = list(name = "New Hampshire Apple Cider Donuts", desc = "Spiced apple cider donuts rolled in cinnamon sugar — a fall orchard staple.", ingredients = "- 2 cups flour\n- 1/2 cup apple cider, reduced to 1/4 cup\n- 1/2 cup sugar\n- 1 egg\n- 1/2 cup buttermilk\n- 1 tsp cinnamon\n- 1 tsp baking powder\n- Oil for frying\n- Cinnamon sugar for rolling", instructions = "1. Reduce cider by half in a saucepan.\n2. Mix dry ingredients.\n3. Mix wet ingredients including reduced cider.\n4. Combine wet and dry.\n5. Fry spoonfuls at 375F until golden.\n6. Roll in cinnamon sugar while hot.", fact = "Fun Fact: New Hampshire's apple orchards produce over 30 varieties of apples and are a major fall tourism destination."),
    "New Mexico" = list(name = "New Mexico Sopapillas with Honey", desc = "Puffy fried dough pillows served with local honey — a New Mexico restaurant tradition.", ingredients = "- 2 cups flour\n- 1 tsp baking powder\n- 1 tsp salt\n- 2 tbsp lard or shortening\n- 3/4 cup warm water\n- Oil for frying\n- Local honey to serve", instructions = "1. Mix flour, baking powder and salt.\n2. Cut in lard until crumbly.\n3. Add water and knead until smooth.\n4. Rest 30 minutes.\n5. Roll thin and cut into triangles.\n6. Fry at 375F until puffed and golden.\n7. Serve immediately with honey.", fact = "Fun Fact: Sopapillas are served at the end of nearly every New Mexican restaurant meal, traditionally filled with honey."),
    "New York" = list(name = "New York Black and White Cookie", desc = "The iconic NYC bakery cookie with half vanilla and half chocolate fondant icing.", ingredients = "- 1.5 cups flour\n- 1/2 cup butter\n- 3/4 cup sugar\n- 2 eggs\n- 1/2 cup sour cream\n- 1 tsp vanilla\n- Vanilla and chocolate fondant icing", instructions = "1. Cream butter and sugar.\n2. Beat in eggs and vanilla.\n3. Alternate adding flour and sour cream.\n4. Scoop onto baking sheets and bake at 375F for 15 minutes.\n5. Ice half with vanilla, half with chocolate fondant.", fact = "Fun Fact: The black and white cookie is so embedded in New York culture that Jerry Seinfeld dedicated an entire episode of his show to it."),
    "North Carolina" = list(name = "North Carolina Hushpuppies", desc = "Crispy cornmeal fritters with a soft, savory interior — a BBQ side staple.", ingredients = "- 1.5 cups cornmeal\n- 1/2 cup flour\n- 1 egg\n- 3/4 cup buttermilk\n- 1 small onion, diced\n- 1 tsp baking powder\n- Salt\n- Oil for frying", instructions = "1. Mix cornmeal, flour, baking powder and salt.\n2. Mix in egg, buttermilk and onion.\n3. Drop spoonfuls into 375F oil.\n4. Fry 3-4 minutes until golden brown.\n5. Drain and serve hot.", fact = "Fun Fact: Hushpuppies got their name from cooks tossing fried cornmeal to quiet barking dogs with 'Hush, puppy!'"),
    "Ohio" = list(name = "Ohio Buckeye Candy", desc = "Peanut butter balls dipped in chocolate to look like Ohio's state tree nut.", ingredients = "- 2 cups peanut butter\n- 3 cups powdered sugar\n- 1/2 cup butter, softened\n- 2 cups chocolate chips\n- 2 tbsp shortening", instructions = "1. Mix peanut butter, powdered sugar and butter until smooth.\n2. Roll into 1-inch balls.\n3. Refrigerate 1 hour.\n4. Melt chocolate and shortening.\n5. Dip each ball leaving a peanut butter circle on top.\n6. Refrigerate until set.", fact = "Fun Fact: Buckeye candy is named for its resemblance to the nut of Ohio's state tree, the Ohio buckeye."),
    "Oklahoma" = list(name = "Oklahoma Chicken Fried Steak", desc = "A tenderized beef cutlet fried in seasoned breading and smothered in cream gravy.", ingredients = "- 4 cube steaks\n- 2 cups flour\n- 2 eggs, beaten\n- 1 cup buttermilk\n- Salt, pepper, garlic powder\n- Oil for frying\n- Cream gravy", instructions = "1. Mix eggs and buttermilk.\n2. Season flour with salt, pepper and garlic powder.\n3. Dip steaks in egg mix then flour, repeat.\n4. Fry at 350F for 4 minutes per side.\n5. Make gravy from drippings, flour and milk.\n6. Smother steaks in gravy.", fact = "Fun Fact: Oklahoma claims chicken fried steak as its official state meal, served alongside mashed potatoes and black-eyed peas."),
    "Oregon" = list(name = "Oregon Marionberry Pie", desc = "A deep, sweet-tart pie made with Oregon's prized Marionberry.", ingredients = "- 4 cups Marionberries (or blackberries)\n- 3/4 cup sugar\n- 3 tbsp cornstarch\n- 1 tbsp lemon juice\n- 2 pie crusts\n- Butter", instructions = "1. Mix berries with sugar, cornstarch and lemon.\n2. Pour into bottom crust.\n3. Dot with butter.\n4. Add top crust and crimp edges.\n5. Cut vents and brush with egg wash.\n6. Bake at 425F for 20 minutes then 350F for 30 minutes.", fact = "Fun Fact: The Marionberry was developed at Oregon State University and named after Marion County, Oregon."),
    "Pennsylvania" = list(name = "Pennsylvania Shoofly Pie", desc = "A molasses-filled pie with a crumbly brown sugar topping — a Pennsylvania Dutch staple.", ingredients = "- 1 pie crust\n- 1 cup molasses\n- 3/4 cup hot water\n- 1 tsp baking soda\n- 1.5 cups flour\n- 1/2 cup brown sugar\n- 1/4 cup butter", instructions = "1. Mix molasses, hot water and baking soda.\n2. Pour into crust.\n3. Mix flour, brown sugar and butter into crumbs.\n4. Sprinkle over molasses layer.\n5. Bake at 375F for 35 minutes.", fact = "Fun Fact: Shoofly pie was named because its sweet molasses filling would attract flies that had to be shooed away."),
    "Rhode Island" = list(name = "Rhode Island Coffee Milk", desc = "The official state drink of Rhode Island — cold milk stirred with sweet coffee syrup.", ingredients = "- 2 cups cold whole milk\n- 3 tbsp Autocrat coffee syrup (or strong coffee syrup)\n- Ice", instructions = "1. Pour cold milk into a tall glass over ice.\n2. Add coffee syrup.\n3. Stir well to combine.\n4. Taste and adjust syrup to preference.\n5. Enjoy immediately.", fact = "Fun Fact: Coffee milk has been Rhode Island's official state drink since 1993, beating out Del's Lemonade in the vote."),
    "South Carolina" = list(name = "South Carolina Boiled Peanuts", desc = "Soft, salty green peanuts boiled in seasoned brine — a beloved Southern roadside snack.", ingredients = "- 2 lbs raw green peanuts\n- 1/2 cup salt\n- Water to cover\n- Optional: Cajun seasoning", instructions = "1. Rinse peanuts thoroughly.\n2. Place in a large pot and cover with water.\n3. Add salt and Cajun seasoning if using.\n4. Boil 3-4 hours until peanuts are soft.\n5. Drain and serve warm.", fact = "Fun Fact: Boiled peanuts are the official snack food of South Carolina and are sold from roadside stands across the state."),
    "South Dakota" = list(name = "South Dakota Kuchen", desc = "A German custard-filled pastry that is South Dakota's official state dessert.", ingredients = "- 2 cups flour\n- 1/4 cup sugar\n- 1/2 cup butter\n- 1 egg\n- Custard filling: 2 eggs, 1 cup cream, 1/2 cup sugar, vanilla", instructions = "1. Make pastry dough with flour, sugar, butter and egg.\n2. Press into a pie pan.\n3. Whisk eggs, cream, sugar and vanilla.\n4. Pour into crust.\n5. Add fruit like peaches or apricots on top.\n6. Bake at 350F for 40 minutes.", fact = "Fun Fact: Kuchen was brought to South Dakota by German-Russian immigrants in the 1870s and declared the state dessert in 2000."),
    "Tennessee" = list(name = "Tennessee Moon Pie", desc = "Chocolate-covered graham cracker and marshmallow sandwiches — a Southern classic.", ingredients = "- 24 graham crackers\n- 2 cups marshmallow fluff\n- 2 cups chocolate chips\n- 2 tbsp coconut oil", instructions = "1. Spread marshmallow fluff on half the graham crackers.\n2. Top with remaining crackers to make sandwiches.\n3. Freeze 30 minutes.\n4. Melt chocolate with coconut oil.\n5. Dip sandwiches in chocolate.\n6. Set on parchment to cool.", fact = "Fun Fact: Moon Pies were invented in Chattanooga, Tennessee in 1917 and are still made there today."),
    "Texas" = list(name = "Texas Sheet Cake", desc = "A massive, thin chocolate cake with warm poured chocolate frosting — a Texas staple.", ingredients = "- 2 cups flour\n- 2 cups sugar\n- 1 cup butter\n- 1 cup water\n- 1/2 cup cocoa (divided)\n- 2 eggs\n- 1/2 cup buttermilk\n- 1 tsp baking soda\n- 1/2 cup milk\n- 1 lb powdered sugar\n- 1 cup pecans", instructions = "1. Boil 1/2 cup butter, water and 1/4 cup cocoa, pour over flour and sugar.\n2. Mix in eggs, buttermilk and baking soda.\n3. Bake in sheet pan at 375F for 20 minutes.\n4. Make frosting: boil remaining butter, milk and cocoa, mix in sugar and pecans.\n5. Pour warm frosting over hot cake.", fact = "Fun Fact: Texas Sheet Cake is called that because it requires a full sheet pan — everything is bigger in Texas."),
    "Utah" = list(name = "Utah Funeral Potatoes", desc = "Creamy, cheesy hash brown casserole with a cornflake topping — Utah's comfort food.", ingredients = "- 1 bag frozen hash browns\n- 1 can cream of chicken soup\n- 1 cup sour cream\n- 2 cups cheddar, shredded\n- 1/2 cup butter, melted\n- 2 cups cornflakes, crushed", instructions = "1. Mix hash browns, soup, sour cream and cheese.\n2. Pour into a greased 9x13.\n3. Mix cornflakes with melted butter.\n4. Spread over top.\n5. Bake at 350F for 45 minutes until bubbly.", fact = "Fun Fact: Funeral potatoes get their name from being the go-to dish brought to LDS church funeral dinners across Utah."),
    "Vermont" = list(name = "Vermont Maple Creemee", desc = "Vermont's legendary soft serve — dense, creamy soft-serve ice cream with real maple syrup.", ingredients = "- 2 cups heavy cream\n- 1 cup whole milk\n- 1/2 cup Vermont maple syrup\n- 1/4 cup sugar\n- 1 tsp vanilla", instructions = "1. Mix all ingredients together until sugar dissolves.\n2. Churn in an ice cream maker according to manufacturer directions.\n3. Serve immediately as soft serve.\n4. Drizzle with extra maple syrup.", fact = "Fun Fact: Vermont produces more maple syrup per capita than any other US state and the maple creemee is a summer institution."),
    "Virginia" = list(name = "Virginia Peanut Soup", desc = "A velvety, rich peanut soup that has been served in Colonial Williamsburg since the 1700s.", ingredients = "- 1 cup peanut butter\n- 4 cups chicken broth\n- 1 onion, diced\n- 2 stalks celery\n- 2 tbsp butter\n- 1 cup cream\n- Chopped peanuts to garnish", instructions = "1. Saute onion and celery in butter until soft.\n2. Add broth and simmer 15 minutes.\n3. Blend until smooth.\n4. Whisk in peanut butter until smooth.\n5. Add cream and heat through.\n6. Serve topped with chopped peanuts.", fact = "Fun Fact: Virginia grows more peanuts than almost any other state and peanut soup has been served in Williamsburg since colonial times."),
    "Washington" = list(name = "Washington Apple Crisp", desc = "A simple, comforting apple crisp made with Washington's prized Honeycrisp apples.", ingredients = "- 6 Washington apples, peeled and sliced\n- 1 cup oats\n- 1/2 cup flour\n- 1/2 cup brown sugar\n- 1/3 cup butter, cold\n- 1 tsp cinnamon\n- Vanilla ice cream to serve", instructions = "1. Layer apples in a greased baking dish.\n2. Mix oats, flour, sugar and cinnamon.\n3. Cut in cold butter until crumbly.\n4. Spread over apples.\n5. Bake at 375F for 40 minutes until golden and bubbly.\n6. Serve warm with ice cream.", fact = "Fun Fact: Washington State produces over 60% of all apples grown in the United States."),
    "West Virginia" = list(name = "West Virginia Pepperoni Roll", desc = "Soft bread rolls stuffed with spicy pepperoni — the official food of West Virginia.", ingredients = "- 1 lb bread dough\n- 1/2 lb pepperoni\n- 1 cup mozzarella\n- Italian seasoning\n- Butter for brushing", instructions = "1. Divide dough into 8 pieces and flatten.\n2. Layer pepperoni and cheese.\n3. Roll up tightly and pinch to seal.\n4. Bake at 375F for 20 minutes.\n5. Brush with butter while hot.", fact = "Fun Fact: The pepperoni roll is the official state food of West Virginia, invented in 1927 as a portable miner's lunch."),
    "Wisconsin" = list(name = "Wisconsin Cheese Curds", desc = "Fresh, squeaky Wisconsin cheese curds battered and deep fried to golden perfection.", ingredients = "- 1 lb fresh cheese curds\n- 1 cup flour\n- 1 cup beer\n- 1 egg\n- Salt and pepper\n- Oil for frying\n- Ranch for dipping", instructions = "1. Make batter with flour, beer, egg, salt and pepper.\n2. Heat oil to 375F.\n3. Dip curds in batter and fry in batches.\n4. Cook 2-3 minutes until golden.\n5. Serve immediately with ranch dipping sauce.", fact = "Fun Fact: Wisconsin produces more cheese than any other state and fresh cheese curds — which squeak when fresh — are a point of state pride."),
    "Wyoming" = list(name = "Wyoming Cowboy Cookies", desc = "Hearty oatmeal cookies loaded with chocolate chips, pecans and coconut.", ingredients = "- 2 cups flour\n- 2 cups oats\n- 1 cup butter\n- 1 cup brown sugar\n- 1/2 cup white sugar\n- 2 eggs\n- 1 cup chocolate chips\n- 1 cup pecans\n- 1/2 cup coconut\n- 1 tsp baking soda", instructions = "1. Cream butter and sugars.\n2. Beat in eggs.\n3. Mix in flour, oats and baking soda.\n4. Fold in chocolate chips, pecans and coconut.\n5. Drop onto baking sheets.\n6. Bake at 350F for 12 minutes.", fact = "Fun Fact: Cowboy cookies are named for their hearty, trail-worthy ingredients that could sustain a long day of ranch work.")
  ),
  
  # ── BEVERAGES ──────────────────────────────────────────────────────────────
  "Beverages" = list(
    "Alabama" = list(name = "Alabama Sweet Tea Brined Chicken", desc = "Chicken brined in sweet tea for a subtle, Southern sweetness.", ingredients = "- 4 chicken thighs\n- 4 cups brewed sweet tea\n- 1/4 cup salt\n- 1 lemon, sliced\n- Black pepper\n- Garlic", instructions = "1. Mix sweet tea, salt, lemon and garlic for brine.\n2. Submerge chicken and refrigerate 4 hours.\n3. Remove, pat dry and season with pepper.\n4. Grill or bake at 425F for 35-40 minutes.\n5. Serve with extra sweet tea.", fact = "Fun Fact: Sweet tea is so central to Southern culture it is sometimes called 'the house wine of the South'."),
    "Arizona" = list(name = "Arizona Horchata Rice Pudding", desc = "Creamy rice pudding infused with the cinnamon and rice flavors of horchata.", ingredients = "- 1 cup rice\n- 4 cups horchata (store-bought or homemade)\n- 1/4 cup sugar\n- 1 tsp cinnamon\n- 1/2 tsp vanilla\n- Raisins optional", instructions = "1. Cook rice in horchata over medium heat, stirring often.\n2. Add sugar, cinnamon and vanilla.\n3. Cook 25-30 minutes until thick and creamy.\n4. Serve warm or chilled with a dusting of cinnamon.", fact = "Fun Fact: Horchata is one of the most popular beverages in Arizona due to the state's large Mexican-American community."),
    "Arkansas" = list(name = "Arkansas Chocolate Gravy and Biscuits", desc = "A uniquely Southern breakfast — rich chocolate gravy poured over fluffy biscuits.", ingredients = "- 2 cups flour\n- 1 tbsp baking powder\n- 1/2 cup butter\n- 3/4 cup milk\n- 3 tbsp cocoa\n- 3 tbsp sugar\n- 2 tbsp flour\n- 2 cups milk\n- Pinch of salt", instructions = "1. Make biscuits and bake at 450F for 12 minutes.\n2. Whisk cocoa, sugar, flour and salt in a saucepan.\n3. Gradually whisk in milk over medium heat.\n4. Stir until thickened, about 5 minutes.\n5. Split biscuits and pour chocolate gravy over top.", fact = "Fun Fact: Chocolate gravy on biscuits is a uniquely Ozark tradition found almost exclusively in Arkansas and surrounding states."),
    "California" = list(name = "California Wine-Braised Short Ribs", desc = "Beef short ribs braised low and slow in California red wine until silky tender.", ingredients = "- 4 lbs bone-in short ribs\n- 1 bottle California Cabernet\n- 1 onion, diced\n- 3 carrots\n- 4 cloves garlic\n- 2 cups beef broth\n- Thyme and rosemary", instructions = "1. Brown short ribs on all sides.\n2. Saute vegetables.\n3. Add wine, broth and herbs.\n4. Return ribs to pot.\n5. Braise covered at 325F for 3.5 hours.\n6. Serve over mashed potatoes with reduced braising liquid.", fact = "Fun Fact: California is the 4th largest wine producer in the world and produces 80% of all US wine."),
    "Colorado" = list(name = "Colorado Craft Beer Braised Brats", desc = "Bratwurst simmered in Colorado craft beer with onions and peppers.", ingredients = "- 6 bratwurst\n- 2 cans Colorado craft lager or amber ale\n- 2 onions, sliced\n- 2 bell peppers, sliced\n- 2 tbsp butter\n- Buns and mustard", instructions = "1. Simmer brats in beer for 20 minutes.\n2. Saute onions and peppers in butter.\n3. Grill brats until charred.\n4. Serve on buns with onions, peppers and mustard.", fact = "Fun Fact: Colorado has more craft breweries per capita than almost any other state."),
    "Connecticut" = list(name = "Connecticut Hard Cider Pork Chops", desc = "Pork chops pan-seared and finished in a tangy Connecticut hard cider and apple sauce.", ingredients = "- 4 bone-in pork chops\n- 1 cup Connecticut hard cider\n- 2 apples, diced\n- 1 shallot, minced\n- 2 tbsp butter\n- Thyme\n- Salt and pepper", instructions = "1. Season chops and sear in butter 4 minutes per side.\n2. Remove and saute shallot and apples.\n3. Add cider and thyme, scraping up browned bits.\n4. Return chops and simmer 10 minutes.\n5. Serve with apple-cider pan sauce.", fact = "Fun Fact: Connecticut has a growing hard cider industry utilizing the state's many apple orchards."),
    "Florida" = list(name = "Florida Orange Juice Glazed Shrimp", desc = "Jumbo shrimp in a sweet, tangy Florida orange glaze over coconut rice.", ingredients = "- 1.5 lbs jumbo shrimp\n- 1 cup fresh Florida orange juice\n- 2 tbsp honey\n- 1 tbsp soy sauce\n- 1 tsp ginger\n- Red pepper flakes\n- Coconut rice to serve", instructions = "1. Reduce orange juice, honey, soy and ginger in a pan.\n2. Season shrimp with salt and red pepper flakes.\n3. Sear shrimp 2 minutes per side.\n4. Toss in orange glaze.\n5. Serve over coconut rice.", fact = "Fun Fact: Florida produces about 70% of the nation's orange juice supply."),
    "Georgia" = list(name = "Georgia Sweet Tea Pulled Chicken", desc = "Chicken slow cooked in sweet tea and peach preserve sauce.", ingredients = "- 3 lbs chicken thighs\n- 2 cups sweet tea\n- 1/2 cup peach preserves\n- 2 tbsp apple cider vinegar\n- 1 tsp garlic powder\n- Salt and pepper", instructions = "1. Mix tea, preserves, vinegar and garlic.\n2. Place chicken in slow cooker.\n3. Pour sauce over chicken.\n4. Cook on low 6-7 hours.\n5. Shred and serve on buns.", fact = "Fun Fact: Georgia is famous for both sweet tea and peaches — combining them is pure Southern genius."),
    "Illinois" = list(name = "Illinois Malted Milkshake Cake", desc = "A nostalgic layer cake flavored with malt powder and vanilla.", ingredients = "- 2 cups flour\n- 1 cup malted milk powder\n- 1 cup butter\n- 2 cups sugar\n- 4 eggs\n- 1 cup milk\n- Vanilla malt frosting", instructions = "1. Cream butter and sugar.\n2. Beat in eggs and vanilla.\n3. Mix in flour, malt powder and milk.\n4. Bake in two 9-inch pans at 350F for 30 minutes.\n5. Frost with vanilla malt buttercream.", fact = "Fun Fact: The malted milkshake was invented in Chicago in 1922 at Walgreens drugstore."),
    "Indiana" = list(name = "Indiana Persimmon Pudding", desc = "A dense, spiced pudding made from Indiana's native wild persimmons.", ingredients = "- 2 cups persimmon pulp\n- 1 cup sugar\n- 2 eggs\n- 1 cup flour\n- 1 cup buttermilk\n- 1 tsp baking soda\n- 1 tsp cinnamon\n- 1/4 tsp nutmeg\n- 2 tbsp butter", instructions = "1. Mix persimmon pulp, sugar and eggs.\n2. Add flour, buttermilk and spices.\n3. Stir in melted butter.\n4. Pour into greased pan.\n5. Bake at 325F for 1 hour until set.\n6. Serve warm with whipped cream.", fact = "Fun Fact: The Mitchell, Indiana Persimmon Festival has celebrated the native fruit every fall since 1946."),
    "Iowa" = list(name = "Iowa Root Beer Float", desc = "A classic American root beer float using Iowa-made root beer.", ingredients = "- 2 cans Iowa craft root beer (or your favorite)\n- 4 scoops vanilla ice cream\n- Whipped cream", instructions = "1. Chill glasses in the freezer 10 minutes.\n2. Add 2 scoops of ice cream to each glass.\n3. Slowly pour root beer over the ice cream.\n4. Top with whipped cream.\n5. Serve with a straw and long spoon.", fact = "Fun Fact: Iowa has a strong craft beverage tradition and several local root beer brands that have been popular for generations."),
    "Kansas" = list(name = "Kansas Iced Coffee Cake", desc = "A moist coffee cake with cinnamon swirl and sweet glaze — perfect with morning coffee.", ingredients = "- 2 cups flour\n- 1 cup sugar\n- 1/2 cup butter\n- 2 eggs\n- 1 cup sour cream\n- 1 tsp vanilla\n- Cinnamon swirl: 1/4 cup sugar, 1 tsp cinnamon\n- Glaze: powdered sugar and milk", instructions = "1. Cream butter and sugar.\n2. Add eggs, sour cream and vanilla.\n3. Fold in flour.\n4. Layer batter and cinnamon swirl in a pan.\n5. Bake at 350F for 35 minutes.\n6. Drizzle with glaze.", fact = "Fun Fact: Coffee cake became a staple of Midwestern hospitality culture, always ready for neighbors who stopped by."),
    "Kentucky" = list(name = "Kentucky Bourbon Bread Pudding", desc = "Crusty bread soaked in custard and baked, then drenched in bourbon caramel sauce.", ingredients = "- 1 loaf stale bread, cubed\n- 4 eggs\n- 2 cups milk\n- 1 cup cream\n- 3/4 cup sugar\n- 2 tsp vanilla\n- Bourbon caramel: 1/2 cup bourbon, 1/2 cup sugar, 1/4 cup butter", instructions = "1. Soak bread cubes in egg-milk-cream-sugar mixture.\n2. Bake at 350F for 45 minutes.\n3. Make caramel: cook sugar until amber, add butter then bourbon carefully.\n4. Pour bourbon caramel over warm pudding.", fact = "Fun Fact: Bourbon is so integral to Kentucky culture that the state produces 95% of the world's supply."),
    "Louisiana" = list(name = "Louisiana Café au Lait Pralines", desc = "New Orleans pecan pralines flavored with chicory coffee.", ingredients = "- 2 cups sugar\n- 1 cup brown sugar\n- 1 cup heavy cream\n- 2 tbsp chicory coffee\n- 3 tbsp butter\n- 2 cups pecans\n- 1 tsp vanilla", instructions = "1. Cook sugars, cream and coffee to 236F (soft ball stage).\n2. Remove from heat and add butter, pecans and vanilla.\n3. Beat until mixture thickens.\n4. Drop spoonfuls onto parchment.\n5. Cool until set.", fact = "Fun Fact: New Orleans café au lait made with chicory coffee has been a morning tradition since the Civil War era."),
    "Maine" = list(name = "Maine Blueberry Lemonade Cake", desc = "A bright lemon cake filled with wild Maine blueberry preserves.", ingredients = "- 2 cups flour\n- 1.5 cups sugar\n- 3/4 cup butter\n- 3 eggs\n- 3/4 cup lemon juice\n- Zest of 2 lemons\n- 1 cup wild blueberry jam\n- Lemon buttercream", instructions = "1. Cream butter and sugar.\n2. Add eggs, lemon juice and zest.\n3. Fold in flour.\n4. Bake in two pans at 350F for 25 minutes.\n5. Fill layers with blueberry jam.\n6. Frost with lemon buttercream.", fact = "Fun Fact: Maine's wild blueberries are smaller and more intensely flavored than cultivated blueberries."),
    "Maryland" = list(name = "Maryland Natty Boh Beer Steamed Crabs", desc = "Blue crabs steamed over beer and Old Bay — the quintessential Maryland summer meal.", ingredients = "- 12 live blue crabs\n- 2 cans National Bohemian beer\n- 1 cup apple cider vinegar\n- Old Bay seasoning — lots of it\n- Salt", instructions = "1. Mix beer and vinegar in the bottom of a large steamer.\n2. Layer crabs in the steamer.\n3. Heavily coat with Old Bay and salt.\n4. Steam 25-30 minutes until bright red.\n5. Serve on newspaper with mallets.", fact = "Fun Fact: National Bohemian 'Natty Boh' beer has been Baltimore's beer since 1885 and its one-eyed mascot is a city icon."),
    "Massachusetts" = list(name = "Massachusetts Sam Adams Onion Soup", desc = "French onion soup made with Samuel Adams Boston Lager for a deep, malty flavor.", ingredients = "- 4 large onions, thinly sliced\n- 1 bottle Sam Adams Boston Lager\n- 2 cups beef broth\n- 3 tbsp butter\n- 1 tsp thyme\n- Baguette slices\n- Gruyere cheese", instructions = "1. Caramelize onions in butter 45 minutes over low heat.\n2. Add beer and reduce by half.\n3. Add broth and thyme, simmer 20 minutes.\n4. Pour into oven-safe bowls.\n5. Top with baguette and gruyere.\n6. Broil until cheese is bubbly.", fact = "Fun Fact: Samuel Adams beer was founded in Boston in 1984 and helped spark America's craft beer revolution."),
    "Michigan" = list(name = "Michigan Vernors Ginger Pork", desc = "Pork tenderloin glazed with Michigan's iconic Vernors ginger ale.", ingredients = "- 2 pork tenderloins\n- 1 cup Vernors ginger ale\n- 2 tbsp soy sauce\n- 1 tbsp brown sugar\n- 1 tsp ginger\n- Garlic and pepper", instructions = "1. Mix Vernors, soy, sugar and ginger for glaze.\n2. Reduce by half in a saucepan.\n3. Season pork and sear until browned.\n4. Brush with glaze and roast at 400F to 145F internal.\n5. Rest and slice, drizzle with remaining glaze.", fact = "Fun Fact: Vernors is the oldest surviving ginger ale brand in America, created in Detroit in 1866."),
    "Minnesota" = list(name = "Minnesota Craft Beer Cheese Soup", desc = "A thick, velvety cheddar soup made with Minnesota craft beer.", ingredients = "- 2 cups Minnesota craft ale\n- 3 cups chicken broth\n- 2 cups sharp cheddar\n- 1 onion, diced\n- 3 tbsp butter\n- 3 tbsp flour\n- 1 cup cream\n- Popcorn or pretzel croutons", instructions = "1. Saute onion in butter.\n2. Whisk in flour and cook 1 minute.\n3. Add beer and broth, whisk until smooth.\n4. Simmer 15 minutes.\n5. Stir in cream and cheese.\n6. Serve topped with popcorn.", fact = "Fun Fact: Minnesota's Twin Cities have one of the highest concentrations of craft breweries of any metro area in the US."),
    "Mississippi" = list(name = "Mississippi Sweet Tea Cake", desc = "A tender butter cake glazed with sweet tea and lemon syrup.", ingredients = "- 2 cups flour\n- 1.5 cups sugar\n- 3/4 cup butter\n- 3 eggs\n- 1/2 cup strong sweet tea\n- 1/2 cup buttermilk\n- Sweet tea glaze: 1/2 cup tea, 1 cup powdered sugar, lemon", instructions = "1. Cream butter and sugar.\n2. Beat in eggs.\n3. Alternate adding flour with tea and buttermilk.\n4. Bake at 350F for 35 minutes.\n5. Poke holes in warm cake.\n6. Pour sweet tea glaze over top.", fact = "Fun Fact: Sweet tea is considered the unofficial drink of Mississippi and is served at nearly every meal."),
    "Missouri" = list(name = "Missouri Craft Root Beer Pulled Pork", desc = "Pulled pork slow cooked in Missouri craft root beer for a sweet, caramel flavor.", ingredients = "- 4 lbs pork shoulder\n- 2 cups craft root beer\n- 1 cup BBQ sauce\n- 1 onion, sliced\n- Garlic powder, salt, pepper", instructions = "1. Place pork in slow cooker with onion.\n2. Pour root beer over pork.\n3. Cook on low 8 hours.\n4. Shred and mix with BBQ sauce.\n5. Serve on buns.", fact = "Fun Fact: Missouri has a thriving craft beverage scene, with numerous artisan root beer producers across the state."),
    "Nebraska" = list(name = "Nebraska Kool-Aid Pickles", desc = "A quirky Nebraska tradition — dill pickles soaked in Kool-Aid for a sweet-sour crunch.", ingredients = "- 1 jar dill pickles\n- 1 packet cherry or tropical Kool-Aid\n- 1/2 cup sugar\n- 1/4 cup pickle juice", instructions = "1. Drain most of the pickle juice, reserve 1/4 cup.\n2. Dissolve Kool-Aid and sugar in reserved juice.\n3. Pour back over pickles.\n4. Refrigerate 3-5 days before eating.\n5. The pickles turn bright red and taste sweet and sour.", fact = "Fun Fact: Kool-Aid was invented in Hastings, Nebraska in 1927 — the state celebrates Kool-Aid Days every August."),
    "Nevada" = list(name = "Nevada Casino-Style Shrimp Cocktail", desc = "Giant chilled shrimp with classic cocktail sauce — a Las Vegas institution since 1959.", ingredients = "- 2 lbs jumbo shrimp, cooked and chilled\n- 1 cup ketchup\n- 2 tbsp horseradish\n- 1 tbsp lemon juice\n- 1 tsp Worcestershire\n- Hot sauce\n- Lemon wedges", instructions = "1. Mix ketchup, horseradish, lemon, Worcestershire and hot sauce.\n2. Refrigerate cocktail sauce 1 hour.\n3. Arrange chilled shrimp on ice.\n4. Serve with cocktail sauce and lemon.", fact = "Fun Fact: The Golden Gate Casino in Las Vegas has been offering a 99-cent shrimp cocktail since 1959, one of the longest-running food deals in history."),
    "New Hampshire" = list(name = "New Hampshire Apple Cider Chicken", desc = "Chicken thighs braised in fresh-pressed New Hampshire apple cider.", ingredients = "- 6 chicken thighs\n- 2 cups New Hampshire apple cider\n- 1 onion, sliced\n- 2 apples, sliced\n- 2 tbsp butter\n- Thyme and rosemary\n- Salt and pepper", instructions = "1. Brown chicken in butter.\n2. Saute onion and apples.\n3. Add cider and herbs.\n4. Return chicken to pan.\n5. Braise covered 30-35 minutes until cooked through.\n6. Reduce sauce and serve.", fact = "Fun Fact: New Hampshire has over 50 apple orchards that press fresh cider each fall season."),
    "New Mexico" = list(name = "New Mexico Agua Fresca", desc = "A refreshing melon and lime agua fresca inspired by New Mexico's love of fresh fruit drinks.", ingredients = "- 4 cups cantaloupe, cubed\n- 2 cups cold water\n- 3 tbsp lime juice\n- 2 tbsp sugar\n- Fresh mint\n- Ice", instructions = "1. Blend cantaloupe with water until smooth.\n2. Strain through a fine mesh strainer.\n3. Add lime juice and sugar, stir to dissolve.\n4. Serve over ice with fresh mint.", fact = "Fun Fact: Agua fresca stands are a beloved part of New Mexico's food culture, with stands appearing at markets and festivals across the state."),
    "New York" = list(name = "New York Egg Cream", desc = "The classic NYC soda fountain drink with no eggs and no cream — just milk, seltzer and chocolate syrup.", ingredients = "- 1/2 cup whole milk, very cold\n- 1/2 cup seltzer water, very cold\n- 2 tbsp Fox's U-Bet chocolate syrup", instructions = "1. Pour milk into a tall glass.\n2. Add chocolate syrup and stir briefly.\n3. Pour cold seltzer down the side of the glass.\n4. Stir vigorously from the bottom — it should foam.\n5. Drink immediately.", fact = "Fun Fact: Despite the name, egg creams contain neither eggs nor cream — the name is debated, but the drink has been a New York City staple since the 1890s."),
    "North Carolina" = list(name = "North Carolina Cheerwine Cake", desc = "A moist, cherry-flavored layer cake made with NC's beloved Cheerwine soda.", ingredients = "- 1 box white cake mix\n- 1 cup Cheerwine cherry soda\n- 3 eggs\n- 1/3 cup oil\n- Cheerwine buttercream: butter, powdered sugar, 3 tbsp Cheerwine reduction", instructions = "1. Mix cake batter substituting Cheerwine for water.\n2. Bake in two pans at 350F per box directions.\n3. Reduce 1/2 cup Cheerwine to 3 tbsp syrup.\n4. Make buttercream with butter, sugar and Cheerwine syrup.\n5. Fill and frost cake.", fact = "Fun Fact: Cheerwine is a cherry soft drink invented in Salisbury, NC in 1917 and still independently owned by the same family."),
    "Ohio" = list(name = "Ohio Skyline Chili Dip", desc = "A layered cream cheese and Cincinnati chili dip inspired by Skyline Chili.", ingredients = "- 8 oz cream cheese, softened\n- 2 cups Cincinnati-style chili\n- 2 cups shredded cheddar\n- Sour cream\n- Tortilla chips", instructions = "1. Spread cream cheese in a baking dish.\n2. Layer chili over cream cheese.\n3. Top with cheddar.\n4. Bake at 350F for 20 minutes until bubbly.\n5. Top with sour cream and serve with chips.", fact = "Fun Fact: Skyline Chili, the Cincinnati chain, serves over a million pounds of chili each year."),
    "Oklahoma" = list(name = "Oklahoma Limeade Pie", desc = "A frozen no-bake pie made with Oklahoma limeade concentrate.", ingredients = "- 1 graham cracker crust\n- 1 can frozen limeade concentrate\n- 1 can sweetened condensed milk\n- 8 oz whipped topping\n- Lime zest", instructions = "1. Mix limeade concentrate and condensed milk.\n2. Fold in whipped topping.\n3. Pour into graham cracker crust.\n4. Freeze 4 hours or overnight.\n5. Garnish with lime zest before serving.", fact = "Fun Fact: Oklahoma's hot summers make frozen citrus desserts a warm-weather staple across the state."),
    "Oregon" = list(name = "Oregon Pinot Noir Beef Stew", desc = "A rich beef stew slow-braised in Oregon Pinot Noir with root vegetables.", ingredients = "- 2 lbs beef chuck, cubed\n- 1 bottle Oregon Pinot Noir\n- 3 carrots, chopped\n- 3 potatoes, cubed\n- 1 onion, diced\n- 4 cloves garlic\n- 2 tbsp tomato paste\n- Thyme and bay leaf", instructions = "1. Brown beef in batches.\n2. Saute onion and garlic.\n3. Add tomato paste and cook 1 minute.\n4. Add wine, broth, herbs and vegetables.\n5. Return beef and braise covered at 325F for 2.5 hours.", fact = "Fun Fact: Oregon's Willamette Valley is considered one of the best Pinot Noir growing regions in the world."),
    "Pennsylvania" = list(name = "Pennsylvania Dutch Birch Beer Float", desc = "A Pennsylvania Dutch tradition — vanilla ice cream in birch beer soda.", ingredients = "- 2 cans Pennsylvania birch beer\n- 4 scoops vanilla ice cream\n- Whipped cream", instructions = "1. Chill glasses in freezer.\n2. Add ice cream to each glass.\n3. Slowly pour birch beer over ice cream.\n4. Top with whipped cream.\n5. Serve immediately.", fact = "Fun Fact: Birch beer is a uniquely Pennsylvania and New England soda made from birch tree extract with a distinctive minty flavor."),
    "Rhode Island" = list(name = "Rhode Island Del's Frozen Lemonade Sorbet", desc = "A homemade version of Rhode Island's beloved Del's lemon ice.", ingredients = "- 6 lemons, juiced\n- 1 cup sugar\n- 2 cups water\n- Lemon zest\n- Pinch of salt", instructions = "1. Make simple syrup with sugar and water.\n2. Mix in lemon juice, zest and salt.\n3. Chill completely.\n4. Churn in ice cream maker or freeze, stirring every hour.\n5. Serve semi-frozen like a slushie.", fact = "Fun Fact: Del's Frozen Lemonade has been a Rhode Island institution since 1948 and was nearly voted the official state drink."),
    "South Carolina" = list(name = "South Carolina Peach Tea Cake", desc = "A summery butter cake soaked with peach tea syrup.", ingredients = "- 2 cups flour\n- 1.5 cups sugar\n- 3/4 cup butter\n- 3 eggs\n- 1/2 cup peach tea\n- 1/2 cup sour cream\n- Peach tea glaze", instructions = "1. Cream butter and sugar.\n2. Add eggs, peach tea and sour cream.\n3. Fold in flour.\n4. Bake in a loaf pan at 350F for 55 minutes.\n5. Poke holes and pour glaze over warm cake.", fact = "Fun Fact: South Carolina is the second largest peach-producing state and combines its peaches with the Southern love of sweet tea."),
    "South Dakota" = list(name = "South Dakota Chokecherry Jelly on Toast", desc = "Wild chokecherry jelly spread on thick buttered toast — a Black Hills tradition.", ingredients = "- Thick-sliced bread\n- Butter\n- Chokecherry jelly (store-bought or homemade)\n- Optional: cream cheese", instructions = "1. Toast bread until golden.\n2. Spread generously with butter.\n3. Top with chokecherry jelly.\n4. Serve with coffee.\n5. Optional: add a layer of cream cheese.", fact = "Fun Fact: Chokecherries grow wild across South Dakota and making chokecherry jelly is a beloved Black Hills tradition."),
    "Tennessee" = list(name = "Tennessee Whiskey Glazed Salmon", desc = "Salmon fillets with a Jack Daniel's Tennessee whiskey and brown sugar glaze.", ingredients = "- 4 salmon fillets\n- 3 tbsp Jack Daniel's whiskey\n- 3 tbsp brown sugar\n- 2 tbsp soy sauce\n- 1 tbsp Dijon mustard\n- Garlic", instructions = "1. Mix whiskey, sugar, soy, mustard and garlic.\n2. Brush over salmon.\n3. Bake at 400F for 15 minutes.\n4. Broil final 2 minutes to caramelize glaze.\n5. Serve with rice or roasted vegetables.", fact = "Fun Fact: Jack Daniel's in Lynchburg, Tennessee is the oldest registered distillery in the US, established in 1866."),
    "Texas" = list(name = "Texas Dr Pepper BBQ Ribs", desc = "Baby back ribs braised in Dr Pepper — a Texas BBQ secret weapon.", ingredients = "- 2 racks baby back ribs\n- 2 cans Dr Pepper\n- 1 cup BBQ sauce\n- 2 tbsp brown sugar\n- 1 tsp garlic powder\n- Salt and pepper", instructions = "1. Season ribs with salt, pepper, sugar and garlic.\n2. Pour Dr Pepper over ribs in a baking dish.\n3. Cover tightly with foil.\n4. Bake at 300F for 3 hours.\n5. Brush with BBQ sauce and grill 10 minutes to caramelize.", fact = "Fun Fact: Dr Pepper was invented in Waco, Texas in 1885, making it the oldest major soft drink brand in America."),
    "Utah" = list(name = "Utah Green Jello Salad", desc = "The iconic Utah lime jello salad with cottage cheese and pineapple.", ingredients = "- 1 box lime Jell-O\n- 1 cup boiling water\n- 1 cup cold water\n- 1 cup cottage cheese\n- 1 can crushed pineapple, drained\n- 1 cup whipped topping", instructions = "1. Dissolve Jell-O in boiling water.\n2. Add cold water and refrigerate until partially set.\n3. Fold in cottage cheese, pineapple and whipped topping.\n4. Pour into mold.\n5. Refrigerate until fully set.", fact = "Fun Fact: Utah consumes more Jell-O per capita than any other state and green Jell-O is considered the unofficial state food."),
    "Vermont" = list(name = "Vermont Hot Apple Cider Donut", desc = "Baked cider donuts glazed with warm spiced cider icing.", ingredients = "- 2 cups flour\n- 1/2 cup Vermont apple cider, reduced\n- 1/2 cup sugar\n- 1 egg\n- 1/2 cup buttermilk\n- 1 tsp cinnamon\n- 1 tsp baking powder\n- Cider glaze: powdered sugar and warm cider", instructions = "1. Reduce 1 cup cider to 1/2 cup.\n2. Mix all donut ingredients.\n3. Bake in donut pan at 375F for 12 minutes.\n4. Make glaze with powdered sugar and warm reduced cider.\n5. Dip warm donuts in glaze.", fact = "Fun Fact: Vermont apple orchards sell fresh cider donuts all fall and they are one of the state's most beloved seasonal foods."),
    "Virginia" = list(name = "Virginia Apple Brandy Cake", desc = "A moist spice cake laced with Virginia apple brandy.", ingredients = "- 2 cups flour\n- 1.5 cups sugar\n- 3/4 cup butter\n- 3 eggs\n- 1/4 cup Virginia apple brandy\n- 1/2 cup apple cider\n- 1 tsp cinnamon\n- 1/2 tsp nutmeg\n- Brandy glaze", instructions = "1. Cream butter and sugar.\n2. Add eggs, brandy and cider.\n3. Mix in flour and spices.\n4. Bake in a bundt pan at 350F for 50 minutes.\n5. Pierce and pour brandy glaze over warm cake.", fact = "Fun Fact: Virginia has been producing apple brandy since colonial times — George Washington himself distilled apple brandy at Mount Vernon."),
    "Washington" = list(name = "Washington Apple Cider Braised Pork", desc = "Pork braised in fresh Washington apple cider with rosemary and thyme.", ingredients = "- 3 lbs pork shoulder\n- 2 cups Washington apple cider\n- 1 onion\n- 3 apples, quartered\n- Rosemary and thyme\n- Salt and pepper", instructions = "1. Brown pork shoulder on all sides.\n2. Add cider, onion, apples and herbs.\n3. Braise covered at 325F for 3 hours.\n4. Shred pork and return to braising liquid.\n5. Serve over mashed potatoes or egg noodles.", fact = "Fun Fact: Washington produces more apples than any other US state and exports them around the world."),
    "West Virginia" = list(name = "West Virginia Ramp and Egg Skillet", desc = "Wild ramps sauteed with eggs and bacon — a spring Appalachian tradition.", ingredients = "- 2 cups wild ramps, cleaned and chopped\n- 4 eggs\n- 4 strips bacon\n- Salt and pepper\n- Butter", instructions = "1. Cook bacon until crispy, crumble and set aside.\n2. Saute ramps in bacon fat until wilted.\n3. Add butter and crack eggs over ramps.\n4. Cook eggs to your preference.\n5. Top with crumbled bacon.", fact = "Fun Fact: Wild ramps are a spring delicacy in Appalachia and West Virginia hosts multiple ramp festivals each April."),
    "Wisconsin" = list(name = "Wisconsin Brandy Old Fashioned", desc = "Wisconsin's beloved twist on the Old Fashioned — made with brandy instead of whiskey.", ingredients = "- 2 oz Korbel brandy\n- 1 sugar cube\n- 2 dashes Angostura bitters\n- Splash of soda\n- Orange slice and cherry\n- Ice", instructions = "1. Muddle sugar cube and bitters in a glass.\n2. Add ice.\n3. Pour brandy over ice.\n4. Add a small splash of soda.\n5. Garnish with orange slice and cherry.", fact = "Fun Fact: Wisconsin consumes more brandy per capita than any other state — nearly a third of all Korbel brandy sold in the US goes to Wisconsin."),
    "Wyoming" = list(name = "Wyoming Cowboy Coffee Cake", desc = "A strong-flavored coffee cake made with cowboy-style campfire coffee.", ingredients = "- 2 cups flour\n- 1 cup strong black coffee\n- 1 cup sugar\n- 1/2 cup butter\n- 2 eggs\n- 1 tsp cinnamon\n- 1 tsp baking soda\n- Streusel topping", instructions = "1. Mix butter, sugar and eggs.\n2. Add strong coffee alternating with flour.\n3. Add cinnamon and baking soda.\n4. Pour into a greased pan.\n5. Top with streusel.\n6. Bake at 350F for 35 minutes.", fact = "Fun Fact: Cowboys on Wyoming cattle drives boiled coffee directly in the pot over campfires, a tradition still celebrated in the state today.")
  ),
  
  # ── DAIRY ──────────────────────────────────────────────────────────────────
  "Dairy" = list(
    "default" = list(name = "Creamy Mac and Cheese", desc = "The ultimate comfort food with a rich, velvety three-cheese sauce.", ingredients = "- 12 oz elbow macaroni\n- 2 tbsp butter\n- 2 tbsp flour\n- 2 cups whole milk\n- 1 cup shredded cheddar\n- 1/2 cup gruyere\n- 1/2 cup parmesan\n- Salt, pepper, mustard powder", instructions = "1. Cook pasta and drain.\n2. Melt butter, whisk in flour.\n3. Slowly whisk in milk until thickened.\n4. Remove from heat and stir in cheeses.\n5. Season and toss with pasta.", fact = "Fun Fact: The average American eats about 9 pounds of cheese per year."),
    "Wisconsin" = list(name = "Wisconsin Beer Cheese Soup", desc = "A thick, velvety soup made with Wisconsin cheddar and local lager.", ingredients = "- 2 cups Wisconsin sharp cheddar\n- 1 cup Wisconsin lager beer\n- 3 cups chicken broth\n- 1 onion, diced\n- 3 tbsp butter\n- 3 tbsp flour\n- 1 cup cream\n- Pretzel croutons", instructions = "1. Saute onion in butter.\n2. Whisk in flour.\n3. Add beer and broth, whisk smooth.\n4. Simmer 15 minutes.\n5. Stir in cream and cheddar.\n6. Serve with pretzel croutons.", fact = "Fun Fact: Wisconsin produces more cheese than any other state — over 3 billion pounds per year."),
    "Vermont" = list(name = "Vermont Cheddar Mac and Cheese", desc = "Extra sharp Vermont white cheddar mac and cheese baked with a breadcrumb crust.", ingredients = "- 12 oz cavatappi pasta\n- 3 cups Vermont extra sharp white cheddar\n- 2 tbsp butter\n- 2 tbsp flour\n- 2 cups whole milk\n- 1/2 cup panko breadcrumbs\n- Salt and white pepper", instructions = "1. Make bechamel with butter, flour and milk.\n2. Stir in Vermont cheddar.\n3. Toss with cooked pasta.\n4. Pour into baking dish.\n5. Top with panko mixed with butter.\n6. Bake at 375F for 25 minutes until golden.", fact = "Fun Fact: Vermont is famous for its aged sharp white cheddar, which has been produced in the state since the 1800s."),
    "California" = list(name = "California Burrata Caprese", desc = "Creamy California burrata with heirloom tomatoes, basil and good olive oil.", ingredients = "- 2 balls fresh burrata\n- 4 heirloom tomatoes, sliced\n- Fresh basil\n- Good olive oil\n- Flaky sea salt\n- Black pepper\n- Balsamic glaze", instructions = "1. Arrange tomato slices on a platter.\n2. Tear burrata and place over tomatoes.\n3. Scatter fresh basil leaves.\n4. Drizzle generously with olive oil.\n5. Season with flaky salt and pepper.\n6. Add balsamic glaze.", fact = "Fun Fact: California produces more dairy than any other state, including over 40% of the nation's butter."),
    "New York" = list(name = "New York Cheesecake", desc = "The definitive dense, creamy New York-style cheesecake with a graham cracker crust.", ingredients = "- 3 lbs cream cheese, softened\n- 1.5 cups sugar\n- 5 eggs\n- 1/2 cup sour cream\n- 1 tsp vanilla\n- Graham cracker crust", instructions = "1. Beat cream cheese and sugar until smooth.\n2. Add eggs one at a time.\n3. Mix in sour cream and vanilla.\n4. Pour into crust.\n5. Bake in water bath at 325F for 1 hour 20 minutes.\n6. Cool completely and refrigerate overnight.", fact = "Fun Fact: New York cheesecake uses cream cheese, which was itself invented in New York in 1872.")
  ),
  
  # ── GRAINS ─────────────────────────────────────────────────────────────────
  "Grains" = list(
    "default" = list(name = "Chicken and Rice Casserole", desc = "A comforting one-dish casserole with tender chicken and perfectly seasoned rice.", ingredients = "- 4 chicken thighs\n- 1.5 cups long grain rice\n- 3 cups chicken broth\n- 1 onion, diced\n- 3 cloves garlic\n- 1 tsp thyme\n- 1 tsp paprika\n- Salt, pepper, olive oil", instructions = "1. Season and sear chicken.\n2. Saute onion and garlic.\n3. Add rice, broth and thyme.\n4. Place chicken on top.\n5. Cover and bake at 375F for 45 minutes.", fact = "Fun Fact: Rice feeds more than half the world's population every day."),
    "Iowa" = list(name = "Iowa Corn Bread Casserole", desc = "A moist, creamy sweet cornbread casserole using Iowa sweet corn.", ingredients = "- 1 can whole kernel corn\n- 1 can creamed corn\n- 1 cup sour cream\n- 1 egg\n- 1 box Jiffy corn muffin mix\n- 1/2 cup butter, melted\n- 1 cup cheddar cheese", instructions = "1. Mix both cans of corn, sour cream, egg, muffin mix and butter.\n2. Pour into greased baking dish.\n3. Top with cheddar.\n4. Bake at 350F for 45 minutes until set and golden.", fact = "Fun Fact: Iowa grows more corn than any other state, producing over 2 billion bushels annually."),
    "Minnesota" = list(name = "Minnesota Wild Rice Soup", desc = "A creamy, comforting soup with Minnesota wild rice, chicken and vegetables.", ingredients = "- 1 cup wild rice\n- 2 cups cooked chicken, shredded\n- 4 cups chicken broth\n- 1 cup cream\n- 1 onion, diced\n- 3 carrots, diced\n- 3 tbsp butter\n- 3 tbsp flour", instructions = "1. Cook wild rice according to package.\n2. Saute onion and carrots in butter.\n3. Whisk in flour, then broth.\n4. Add chicken and wild rice.\n5. Simmer 20 minutes.\n6. Stir in cream and serve.", fact = "Fun Fact: Wild rice is Minnesota's official state grain and has been harvested by the Ojibwe people for centuries."),
    "Louisiana" = list(name = "Louisiana Dirty Rice", desc = "Cajun seasoned rice cooked with chicken livers, sausage and the holy trinity.", ingredients = "- 2 cups long grain rice\n- 1/2 lb chicken livers, minced\n- 1/2 lb ground pork\n- 1 onion\n- 3 stalks celery\n- 1 bell pepper\n- 4 cloves garlic\n- Cajun seasoning\n- Chicken broth", instructions = "1. Brown chicken livers and pork together.\n2. Add onion, celery, pepper and garlic.\n3. Season with Cajun seasoning.\n4. Add rice and broth.\n5. Cook covered until rice is done, about 20 minutes.", fact = "Fun Fact: Louisiana is the largest rice-producing state east of the Mississippi River."),
    "Texas" = list(name = "Texas Jalapeño Cheddar Cornbread", desc = "Cast iron cornbread loaded with jalapeños, cheddar and a hint of honey.", ingredients = "- 1.5 cups cornmeal\n- 1/2 cup flour\n- 1 cup buttermilk\n- 2 eggs\n- 1/4 cup honey\n- 1/4 cup butter, melted\n- 2 jalapeños, diced\n- 1 cup sharp cheddar", instructions = "1. Heat cast iron skillet in 425F oven.\n2. Mix all ingredients.\n3. Pour into hot skillet.\n4. Bake 20-25 minutes until golden.", fact = "Fun Fact: Cornbread cooked in a cast iron skillet has been a Texas staple since the days of cattle drives.")
  ),
  
  # ── FRUITS ─────────────────────────────────────────────────────────────────
  "Fruits" = list(
    "default" = list(name = "Mango Glazed Salmon", desc = "A sweet and savory salmon fillet with a sticky mango glaze and fresh fruit salsa.", ingredients = "- 4 salmon fillets\n- 1 ripe mango, diced\n- 2 tbsp soy sauce\n- 1 tbsp honey\n- 1 lime, juiced\n- 1/2 red onion\n- Fresh cilantro\n- Salt and pepper", instructions = "1. Mix soy, honey and lime for glaze.\n2. Season salmon and brush with glaze.\n3. Bake at 400F for 15 minutes.\n4. Mix mango, onion and cilantro for salsa.\n5. Serve salmon topped with salsa.", fact = "Fun Fact: Mangoes are the most widely consumed fruit in the world."),
    "Georgia" = list(name = "Georgia Peach and Arugula Salad", desc = "Fresh Georgia peaches over peppery arugula with pecans and honey balsamic dressing.", ingredients = "- 4 ripe Georgia peaches, sliced\n- 4 cups arugula\n- 1/2 cup pecans, toasted\n- 4 oz goat cheese\n- 3 tbsp honey\n- 2 tbsp balsamic vinegar\n- 3 tbsp olive oil", instructions = "1. Whisk honey, balsamic and olive oil.\n2. Toss arugula with half the dressing.\n3. Arrange on plates.\n4. Top with peaches, pecans and goat cheese.\n5. Drizzle with remaining dressing.", fact = "Fun Fact: Georgia peaches are harvested June through August and are prized worldwide for their sweetness."),
    "Florida" = list(name = "Florida Key Lime Pie", desc = "The authentic Key lime pie with a tangy custard filling and buttery graham crust.", ingredients = "- 1 graham cracker crust\n- 4 egg yolks\n- 1 can sweetened condensed milk\n- 1/2 cup Key lime juice\n- Whipped cream", instructions = "1. Whisk egg yolks with condensed milk.\n2. Add Key lime juice and mix.\n3. Pour into crust.\n4. Bake at 325F for 15 minutes.\n5. Cool completely and serve with whipped cream.", fact = "Fun Fact: Key lime pie is the official state pie of Florida and must be made with authentic Key lime juice to be authentic."),
    "California" = list(name = "California Strawberry Avocado Toast", desc = "Creamy avocado on sourdough topped with fresh California strawberries and honey.", ingredients = "- 4 slices sourdough bread\n- 2 avocados\n- 1 cup California strawberries, sliced\n- Honey\n- Flaky salt\n- Red pepper flakes\n- Lemon juice", instructions = "1. Toast sourdough bread.\n2. Mash avocado with lemon, salt and pepper flakes.\n3. Spread on toast.\n4. Top with strawberries.\n5. Drizzle with honey and sprinkle with flaky salt.", fact = "Fun Fact: California grows about 90% of all strawberries produced in the United States."),
    "Washington" = list(name = "Washington Apple Galette", desc = "A rustic free-form pastry filled with Washington Honeycrisp apples and brown sugar.", ingredients = "- 1 pie crust\n- 4 Washington apples, thinly sliced\n- 1/4 cup brown sugar\n- 1 tsp cinnamon\n- 2 tbsp butter\n- 1 egg for wash", instructions = "1. Roll crust into a rough circle on parchment.\n2. Toss apples with sugar and cinnamon.\n3. Pile in center leaving a 2 inch border.\n4. Fold edges over apples.\n5. Brush crust with egg wash.\n6. Dot filling with butter.\n7. Bake at 400F for 35-40 minutes.", fact = "Fun Fact: Washington produces over 60% of all apples grown in the United States."),
    "Maine" = list(name = "Maine Wild Blueberry Pancakes", desc = "Fluffy buttermilk pancakes bursting with wild Maine blueberries.", ingredients = "- 2 cups flour\n- 2 cups buttermilk\n- 2 eggs\n- 3 tbsp sugar\n- 1 tsp baking powder\n- 1 tsp baking soda\n- 2 cups wild Maine blueberries\n- Butter for cooking", instructions = "1. Mix dry ingredients.\n2. Whisk buttermilk and eggs.\n3. Fold wet into dry — lumps are okay.\n4. Fold in blueberries.\n5. Cook in butter on a griddle until bubbles form, then flip.\n6. Serve with maple syrup.", fact = "Fun Fact: Maine produces 99% of all wild blueberries grown in the US — they're smaller and more flavorful than farmed blueberries.")
  ),
  
  # ── VEGETABLES ─────────────────────────────────────────────────────────────
  "Vegetables" = list(
    "default" = list(name = "Roasted Vegetable Pasta", desc = "A vibrant pasta tossed with oven-roasted vegetables and garlic olive oil.", ingredients = "- 12 oz penne\n- 1 zucchini\n- 1 cup cherry tomatoes\n- 1 red onion\n- 1 cup broccoli\n- 3 tbsp olive oil\n- 4 cloves garlic\n- Salt, pepper, red pepper flakes\n- Parmesan", instructions = "1. Roast vegetables at 425F for 25 minutes.\n2. Cook pasta and reserve pasta water.\n3. Saute garlic in olive oil.\n4. Toss pasta with garlic oil and roasted vegetables.\n5. Add pasta water as needed.", fact = "Fun Fact: Tomatoes were once considered poisonous in the United States."),
    "Louisiana" = list(name = "Louisiana Smothered Okra", desc = "Tender okra smothered with tomatoes, onion and Cajun spices over rice.", ingredients = "- 2 lbs fresh okra, sliced\n- 1 can diced tomatoes\n- 1 onion, diced\n- 1 bell pepper\n- 4 cloves garlic\n- Cajun seasoning\n- Olive oil\n- Cooked rice", instructions = "1. Saute onion, pepper and garlic in oil.\n2. Add okra and cook 10 minutes.\n3. Add tomatoes and Cajun seasoning.\n4. Simmer 20 minutes until okra is tender.\n5. Serve over rice.", fact = "Fun Fact: Okra is a cornerstone of Louisiana Cajun and Creole cooking and is used as a thickener in gumbo."),
    "New Mexico" = list(name = "New Mexico Roasted Green Chile Stew", desc = "A hearty pork and potato stew loaded with roasted New Mexico green chiles.", ingredients = "- 1 lb pork shoulder, cubed\n- 6 New Mexico green chiles, roasted and peeled\n- 3 potatoes, diced\n- 1 onion\n- 4 cloves garlic\n- 3 cups chicken broth\n- Salt and cumin", instructions = "1. Brown pork in a large pot.\n2. Add onion and garlic.\n3. Add broth, potatoes, cumin and salt.\n4. Chop roasted chiles and add to pot.\n5. Simmer 30 minutes until potatoes are tender.", fact = "Fun Fact: New Mexico grows more chile peppers than any other US state and the green chile harvest is a major annual event."),
    "California" = list(name = "California Buddha Bowl", desc = "A nourishing bowl with roasted sweet potato, avocado, quinoa and tahini dressing.", ingredients = "- 2 sweet potatoes, cubed\n- 2 cups cooked quinoa\n- 2 avocados\n- 2 cups kale\n- 1 cup chickpeas, roasted\n- Tahini dressing: tahini, lemon, garlic, water", instructions = "1. Roast sweet potato and chickpeas at 400F for 25 minutes.\n2. Cook quinoa.\n3. Massage kale with olive oil and salt.\n4. Whisk tahini dressing.\n5. Assemble bowls with all components.\n6. Drizzle with tahini dressing.", fact = "Fun Fact: California grows more than 400 different commodities and is the top agricultural state in the US."),
    "Texas" = list(name = "Texas Smoked Elote", desc = "Mexican street corn smoked on the grill, slathered in cotija and chile lime butter.", ingredients = "- 6 ears of corn\n- 1/2 cup mayonnaise\n- 1/2 cup cotija cheese\n- 1 tbsp chili powder\n- Lime juice\n- Fresh cilantro\n- Smoked paprika", instructions = "1. Grill corn in husks over indirect heat 20 minutes.\n2. Pull back husks.\n3. Brush with mayonnaise.\n4. Roll in cotija cheese.\n5. Sprinkle with chili powder and smoked paprika.\n6. Finish with lime juice and cilantro.", fact = "Fun Fact: Texas grows more varieties of hot peppers than any other state and Tex-Mex food has been a cultural staple since the 1800s.")
  ),
  
  # ── FATS AND OILS ──────────────────────────────────────────────────────────
  "Fats and oils" = list(
    "default" = list(name = "Golden Garlic Butter Shrimp Pasta", desc = "Succulent shrimp in a rich garlic butter sauce over linguine.", ingredients = "- 12 oz linguine\n- 1 lb shrimp\n- 4 tbsp butter\n- 3 tbsp olive oil\n- 5 cloves garlic\n- 1/2 cup white wine\n- Lemon\n- Parsley\n- Salt and red pepper flakes", instructions = "1. Cook pasta and reserve pasta water.\n2. Heat butter and oil, saute garlic.\n3. Cook shrimp 2 minutes per side.\n4. Add wine and lemon, simmer.\n5. Toss with pasta.", fact = "Fun Fact: Olive oil has been produced in the Mediterranean for over 6,000 years."),
    "California" = list(name = "California Avocado Oil Seared Halibut", desc = "Pacific halibut seared in avocado oil with lemon, capers and herb butter.", ingredients = "- 4 halibut fillets\n- 2 tbsp avocado oil\n- 3 tbsp butter\n- 2 tbsp capers\n- 2 cloves garlic\n- Lemon\n- Fresh parsley", instructions = "1. Pat halibut dry and season.\n2. Sear in avocado oil 4 minutes per side.\n3. Remove fish and add butter, garlic and capers.\n4. Cook 1 minute until fragrant.\n5. Pour pan sauce over fish.", fact = "Fun Fact: California produces about 95% of all avocados grown in the United States."),
    "Georgia" = list(name = "Georgia Peanut Oil Fried Chicken", desc = "Extra crispy fried chicken cooked in Georgia peanut oil.", ingredients = "- 4 lbs chicken pieces\n- 2 cups buttermilk\n- 2 cups flour\n- 1 tsp each: paprika, garlic powder, cayenne\n- Salt and pepper\n- Georgia peanut oil for frying", instructions = "1. Soak chicken in buttermilk overnight.\n2. Season flour with spices.\n3. Dredge chicken in seasoned flour.\n4. Fry in peanut oil at 350F for 15-18 minutes.\n5. Drain and serve hot.", fact = "Fun Fact: Georgia peanut oil has a high smoke point and a neutral flavor that makes it ideal for frying."),
    "Texas" = list(name = "Texas Chicken Fried in Pecan Oil", desc = "Buttermilk fried chicken cooked in Texas pecan oil with cream gravy.", ingredients = "- 4 chicken thighs\n- 2 cups buttermilk\n- 2 cups flour\n- Texas pecan oil for frying\n- Cream gravy: drippings, flour, milk\n- Salt and pepper", instructions = "1. Marinate chicken in buttermilk.\n2. Dredge in seasoned flour.\n3. Fry in pecan oil at 350F until golden.\n4. Make gravy from drippings.\n5. Serve chicken smothered in cream gravy.", fact = "Fun Fact: Texas is one of the top pecan-producing states and pecan oil has a rich, nutty flavor.")
  ),
  
  # ── SUGAR AND SWEETENERS ───────────────────────────────────────────────────
  "Sugar and sweeteners" = list(
    "default" = list(name = "Honey Garlic Glazed Pork Tenderloin", desc = "Tender pork with a sticky, caramelized honey garlic glaze.", ingredients = "- 2 pork tenderloins\n- 3 tbsp honey\n- 4 cloves garlic\n- 2 tbsp soy sauce\n- 1 tbsp olive oil\n- 1 tsp Dijon mustard\n- Salt and pepper", instructions = "1. Mix honey, garlic, soy and mustard.\n2. Season and sear pork.\n3. Brush with honey glaze.\n4. Roast at 400F to 145F internal.\n5. Rest and slice.", fact = "Fun Fact: Honey never spoils. Honey found in Egyptian tombs was still edible after 3,000 years."),
    "Vermont" = list(name = "Vermont Maple Syrup Tart", desc = "A rich custard tart made entirely with Vermont Grade A dark maple syrup.", ingredients = "- 1 tart shell, blind baked\n- 3/4 cup Vermont dark maple syrup\n- 3 eggs\n- 1 cup heavy cream\n- 1 tsp vanilla\n- Pinch of salt", instructions = "1. Whisk eggs, maple syrup, cream, vanilla and salt.\n2. Pour into blind-baked tart shell.\n3. Bake at 325F for 30-35 minutes until set.\n4. Cool completely.\n5. Serve with whipped cream.", fact = "Fun Fact: Vermont produces more maple syrup per capita than any other US state and is the top maple syrup producer."),
    "Louisiana" = list(name = "Louisiana Praline Cookies", desc = "Brown sugar pecan praline cookies inspired by New Orleans confectionery.", ingredients = "- 1 cup brown sugar\n- 1/2 cup butter\n- 1 egg\n- 1 tsp vanilla\n- 1.5 cups flour\n- 1/2 tsp baking soda\n- 1.5 cups pecans, chopped", instructions = "1. Cream butter and brown sugar.\n2. Add egg and vanilla.\n3. Mix in flour and baking soda.\n4. Fold in pecans.\n5. Scoop onto baking sheets.\n6. Bake at 375F for 10-12 minutes.", fact = "Fun Fact: New Orleans pralines are made with cane sugar grown in Louisiana's sugarcane fields."),
    "Georgia" = list(name = "Georgia Peach Preserves on Biscuits", desc = "Homemade Georgia peach preserves spooned over hot buttery biscuits.", ingredients = "- 3 lbs Georgia peaches, peeled and diced\n- 2 cups sugar\n- 2 tbsp lemon juice\n- 2 cups flour\n- 1 tbsp baking powder\n- 1/2 cup cold butter\n- 3/4 cup buttermilk", instructions = "1. Cook peaches, sugar and lemon until thick, about 30 minutes.\n2. Make biscuits: mix flour and baking powder, cut in cold butter.\n3. Add buttermilk and mix.\n4. Bake at 450F for 12 minutes.\n5. Split biscuits and spoon warm preserves over top.", fact = "Fun Fact: Georgia peaches are so sweet they require less added sugar than almost any other fruit for preserves."),
    "Hawaii" = list(name = "Hawaiian Shave Ice with Li Hing Syrup", desc = "Finely shaved ice drizzled with tropical syrups and li hing mui powder.", ingredients = "- Shaved ice or finely crushed ice\n- Passion fruit syrup\n- Coconut syrup\n- Li hing mui powder\n- Optional: sweetened condensed milk", instructions = "1. Finely shave or crush ice into a cone shape.\n2. Drizzle with passion fruit and coconut syrup.\n3. Dust with li hing mui powder.\n4. Add condensed milk for a snow cap.\n5. Eat immediately.", fact = "Fun Fact: Shave ice was introduced to Hawaii by Japanese immigrants and is now one of the state's most iconic treats.")
  ),
  
  # ── OTHER ──────────────────────────────────────────────────────────────────
  "Other" = list(
    "default" = list(name = "Cozy Vegetable Soup", desc = "A warming, wholesome soup perfect for any night of the week.", ingredients = "- 2 carrots, diced\n- 2 celery stalks, diced\n- 1 onion, diced\n- 2 potatoes, cubed\n- 4 cups vegetable broth\n- 1 can diced tomatoes\n- Salt, pepper, thyme", instructions = "1. Saute onion, carrots and celery 5 minutes.\n2. Add potatoes, broth and tomatoes.\n3. Season with salt, pepper and thyme.\n4. Bring to a boil then simmer 20 minutes.\n5. Adjust seasoning and serve.", fact = "Fun Fact: Soup is one of the oldest prepared foods, with evidence of soup-making dating back 20,000 years."),
    "Louisiana" = list(name = "Louisiana Gumbo", desc = "The soul of Louisiana cooking — a rich, dark roux-based stew with shrimp, andouille and okra.", ingredients = "- 1/2 cup oil\n- 1/2 cup flour\n- 1 onion\n- 3 stalks celery\n- 1 bell pepper\n- 4 cloves garlic\n- 1 lb andouille sausage\n- 1 lb shrimp\n- 1 cup okra\n- 4 cups chicken broth\n- Cajun seasoning\n- File powder\n- Cooked rice", instructions = "1. Make dark roux with oil and flour, cook 30-40 minutes until chocolate brown.\n2. Add trinity (onion, celery, pepper) and cook 5 minutes.\n3. Add garlic, broth and sausage.\n4. Simmer 45 minutes.\n5. Add shrimp and okra, cook 10 minutes.\n6. Season and serve over rice with file powder.", fact = "Fun Fact: Gumbo is Louisiana's official state cuisine and the word comes from the Bantu word for okra."),
    "New Mexico" = list(name = "New Mexico Frito Pie", desc = "Fritos corn chips smothered in red chile and topped with cheese and onion.", ingredients = "- 1 bag Fritos corn chips\n- 2 cups New Mexico red chile sauce\n- 1 cup shredded cheddar\n- 1/2 onion, diced\n- Sour cream\n- Jalapeños", instructions = "1. Warm red chile sauce.\n2. Open a bag of Fritos.\n3. Pour warm red chile directly into the bag or into a bowl.\n4. Top with cheese, onion, sour cream and jalapeños.\n5. Eat immediately.", fact = "Fun Fact: Frito Pie is so beloved in New Mexico it is served at the Santa Fe Five and Dime straight from the Fritos bag."),
    "Texas" = list(name = "Texas Chili con Carne", desc = "The real Texas chili — beef, dried chiles and spices, absolutely no beans.", ingredients = "- 3 lbs beef chuck, cubed\n- 4 dried ancho chiles\n- 2 dried guajillo chiles\n- 1 onion\n- 4 cloves garlic\n- 2 cups beef broth\n- 1 tsp cumin\n- Salt", instructions = "1. Toast and rehydrate dried chiles, blend into a paste.\n2. Brown beef in batches.\n3. Saute onion and garlic.\n4. Add chile paste, broth and cumin.\n5. Return beef and simmer 2 hours.\n6. No beans — ever.", fact = "Fun Fact: True Texas chili, called 'bowl of red', never contains beans — that is considered heresy in Texas."),
    "Pennsylvania" = list(name = "Pennsylvania Scrapple", desc = "A Pennsylvania Dutch pork and cornmeal loaf, sliced and pan-fried until crispy.", ingredients = "- 1 lb ground pork\n- 1 cup cornmeal\n- 3 cups water\n- 1 tsp sage\n- 1 tsp thyme\n- Salt and pepper\n- Oil for frying", instructions = "1. Cook pork in water until done, crumble finely.\n2. Add cornmeal and seasonings, stir until thick.\n3. Pour into loaf pan and refrigerate overnight.\n4. Slice 1/2 inch thick.\n5. Pan fry in oil until crispy on both sides.\n6. Serve with maple syrup or eggs.", fact = "Fun Fact: Scrapple is a Pennsylvania Dutch specialty made since colonial times as a way to use every part of the hog."),
    "Minnesota" = list(name = "Minnesota Tater Tot Hot Dish", desc = "The ultimate Minnesota comfort food — ground beef, green beans and cream of mushroom topped with tater tots.", ingredients = "- 1 lb ground beef\n- 1 bag frozen tater tots\n- 1 can cream of mushroom soup\n- 1 can green beans, drained\n- 1 onion, diced\n- 1 cup cheddar\n- Salt and pepper", instructions = "1. Brown beef and onion.\n2. Mix with soup and green beans.\n3. Pour into greased 9x13.\n4. Top with cheddar and tater tots.\n5. Bake at 375F for 40-45 minutes until bubbly.", fact = "Fun Fact: Hot dish is so Minnesotan that the phrase itself is considered a regional identity marker — not 'casserole', always 'hot dish'.")
  ),
  
  # ── ALCOHOL ────────────────────────────────────────────────────────────────
  "Alcohol" = list(
    "default" = list(name = "Beer Braised Beef Stew", desc = "A deeply rich beef stew slow-cooked in a savory beer broth.", ingredients = "- 2 lbs beef chuck, cubed\n- 1 bottle dark beer\n- 2 cups beef broth\n- 3 carrots\n- 3 potatoes, cubed\n- 1 onion\n- 3 cloves garlic\n- 2 tbsp tomato paste\n- Salt, pepper, thyme", instructions = "1. Brown beef in batches.\n2. Saute onion and garlic.\n3. Add tomato paste and cook 1 minute.\n4. Add beer, broth, thyme and vegetables.\n5. Simmer covered 2 hours.", fact = "Fun Fact: Beer has been brewed for at least 7,000 years."),
